import { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import SpaceCard from '../components/SpaceCard';
import MapView from '../components/MapView';
import Filters from '../components/Filters';
import searchImage from '../images/infralist-com-kmIKEGO7Vl4-unsplash.jpg';
import { getSpaces, getFilters } from '../services/spaceService';
import { getFavorites } from '../services/favoritesService';
import { useAuth } from '../hooks/useAuth';
function useFavorites() {
  const [fav, setFav] = useState([]);
  const { user } = useAuth();
  useEffect(() => {
    const loadFavorites = async () => {
      if (!user) {
        setFav([]);
        return;
      }
      try {
        const data = await getFavorites();
        const favIds = (data.favorites || []).map(f => f._id || f.space?._id || f.space);
        setFav(favIds);
      } catch (err) {
        console.error('Error loading favorites:', err);
        setFav([]);
      }
    };
    loadFavorites();
  }, [user]);
  const toggle = (id) => setFav((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  return { favorites: fav, toggle };
}
export default function Search() {
  const [filterValues, setFilterValues] = useState({ city: '', type: '', minPrice: '', maxPrice: '' });
  const { favorites, toggle } = useFavorites();
  const [sortBy, setSortBy] = useState('relevance');
  const [showMap, setShowMap] = useState(false);
  const [searchParams] = useSearchParams();
  const [spaces, setSpaces] = useState([]);
  const [cities, setCities] = useState([]);
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  useEffect(() => {
    const loadFilters = async () => {
      try {
        const data = await getFilters();
        setCities(data.cities || []);
        setTypes(data.types || []);
      } catch (err) {
        console.error('Error loading filters:', err);
      }
    };
    loadFilters();
  }, []);
  useEffect(() => {
    const type = searchParams.get('type') || '';
    const city = searchParams.get('city') || '';
    const minPrice = searchParams.get('minPrice') || '';
    const maxPrice = searchParams.get('maxPrice') || '';
    const sort = searchParams.get('sort') || '';

    setFilterValues({
      city,
      type,
      minPrice,
      maxPrice
    });

    if (sort) setSortBy(sort);
  }, [searchParams]);

  useEffect(() => {
    const loadSpaces = async () => {
      try {
        setLoading(true);
        setError(null);
        const filters = {
          city: filterValues.city || undefined,
          type: filterValues.type || undefined,
          minPrice: filterValues.minPrice || undefined,
          maxPrice: filterValues.maxPrice || undefined,
          limit: 100
        };
        let sort = 'pricePerDay';
        if (sortBy === 'price-asc') sort = 'pricePerDay';
        else if (sortBy === 'price-desc') sort = '-pricePerDay';
        else if (sortBy === 'rating-desc') sort = '-rating';
        filters.sort = sort;
        const response = await getSpaces(filters);
        setSpaces(response.data || []);
      } catch (err) {
        console.error('Error loading spaces:', err);
        setError(err.message || 'Failed to load spaces');
        setSpaces([]);
      } finally {
        setLoading(false);
      }
    };
    loadSpaces();
  }, [filterValues, sortBy]);
  const heroSelectClass =
    'h-12 min-w-[200px] px-4 rounded-xl border border-white/25 bg-white/15 backdrop-blur-md ' +
    'text-white font-medium shadow-lg shadow-black/20 ' +
    'focus:outline-none focus:ring-2 focus:ring-blue-400/80 focus:border-transparent ' +
    '[color-scheme:dark]';

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-gray-950 bg-[length:24px_24px] bg-grid-pattern dark:bg-none">
      <Navbar />
      <main className="flex-1">
        <section className="relative h-[50vh] min-h-[400px] flex items-center justify-center overflow-hidden">
          <div className="absolute inset-0">
            <img
              src={searchImage}
              alt=""
              className="h-full w-full object-cover scale-105"
            />
            <div className="absolute inset-0 bg-gradient-to-br from-gray-900/85 via-blue-950/55 to-indigo-950/80" />
            <div className="pointer-events-none absolute -left-32 top-20 h-72 w-72 rounded-full bg-blue-500/25 blur-3xl" />
            <div className="pointer-events-none absolute -right-20 bottom-10 h-64 w-64 rounded-full bg-indigo-500/20 blur-3xl" />
          </div>
          <div className="relative z-10 mx-auto max-w-full px-6 text-center text-white md:px-12 lg:px-16">
            <p className="mb-4 inline-flex items-center gap-2 rounded-full border border-white/15 bg-white/10 px-4 py-1.5 text-xs font-semibold uppercase tracking-[0.2em] text-blue-100/90 backdrop-blur-md">
              Search
            </p>
            <h1 className="mb-4 text-4xl font-extrabold tracking-tight md:text-6xl">
              Explore{' '}
              <span className="bg-gradient-to-r from-sky-300 to-blue-400 bg-clip-text text-transparent">
                Workspaces
              </span>
            </h1>
            <p className="mx-auto mb-10 max-w-2xl text-lg text-gray-200 md:text-xl">
              Find the perfect space for your team — filter by city, type, and budget.
            </p>
            <div className="flex flex-col items-center justify-center gap-3 sm:flex-row sm:gap-4">
              <div className="flex items-center gap-3 rounded-2xl border border-white/20 bg-white/10 px-5 py-3 shadow-lg backdrop-blur-md">
                <div className="flex h-11 w-11 items-center justify-center rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 shadow-lg">
                  <span className="text-lg font-bold tabular-nums">
                    {loading ? '…' : spaces.length}
                  </span>
                </div>
                <div className="text-left">
                  <div className="text-xs font-medium uppercase tracking-wide text-blue-100/80">
                    Matches
                  </div>
                  <div className="font-semibold">results</div>
                </div>
              </div>
              <select
                className={heroSelectClass}
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                aria-label="Sort results"
              >
                <option value="relevance" className="bg-slate-900 text-white">
                  Sort: Relevance
                </option>
                <option value="price-asc" className="bg-slate-900 text-white">
                  Price: Low to High
                </option>
                <option value="price-desc" className="bg-slate-900 text-white">
                  Price: High to Low
                </option>
                <option value="rating-desc" className="bg-slate-900 text-white">
                  Rating: High to Low
                </option>
              </select>
              <button
                type="button"
                className={`h-12 rounded-xl px-6 font-semibold transition-all ${
                  showMap
                    ? 'bg-gradient-to-r from-blue-500 to-indigo-600 text-white shadow-lg shadow-blue-900/40'
                    : 'border border-white/25 bg-white/10 text-white backdrop-blur-md hover:bg-white/20'
                }`}
                onClick={() => setShowMap(!showMap)}
              >
                {showMap ? 'List view' : 'Map view'}
              </button>
            </div>
          </div>
        </section>
        <section className="py-8 md:py-10">
          <div className="mx-auto max-w-full px-6 md:px-12 lg:px-16">
            <div className="relative mb-6 rounded-2xl p-[1px] shadow-soft dark:shadow-soft-dark">
              <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-brand-400/30 via-transparent to-indigo-500/25 dark:from-brand-500/20 dark:to-indigo-600/20" />
              <div className="relative rounded-2xl border border-gray-100/80 bg-white/95 p-6 backdrop-blur-sm dark:border-gray-700/80 dark:bg-gray-900/80">
                <Filters
                  cities={cities}
                  types={types}
                  values={filterValues}
                  onChange={setFilterValues}
                />
              </div>
            </div>
            {loading ? (
              <div className="col-span-full py-16 text-center">
                <svg className="animate-spin h-12 w-12 text-blue-600 mx-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                <p className="mt-4 text-gray-600 dark:text-gray-400">Loading spaces...</p>
              </div>
            ) : error ? (
              <div className="col-span-full py-16 text-center">
                <div className="w-16 h-16 mx-auto rounded-full bg-red-100 flex items-center justify-center mb-4">
                  <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">Error loading spaces</h3>
                <p className="text-gray-600 dark:text-gray-300">{error}</p>
              </div>
            ) : !showMap ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {spaces.length === 0 ? (
                  <div className="col-span-full py-16 text-center">
                    <div className="w-16 h-16 mx-auto rounded-full bg-gray-100 flex items-center justify-center mb-4">
                      <svg className="w-8 h-8 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                    </div>
                    <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">No spaces found</h3>
                    <p className="text-gray-600 dark:text-gray-300">Try adjusting your filters to see more results.</p>
                  </div>
                ) : (
                  spaces.map((s) => (
                      <SpaceCard
                        key={s._id || s.id}
                        space={s}
                        onToggleFavorite={toggle}
                        isFavorite={favorites.includes(s._id || s.id)}
                      />
                    ))
                )}
              </div>
            ) : (
              <div className="rounded-2xl overflow-hidden border border-gray-200 shadow-lg">
                <MapView spaces={spaces} />
              </div>
            )}
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
}
